# Claude Code Taskbar Badge - Installer
# Per-tab status badge (working/waiting/done) on Windows Terminal taskbar icon.
# Requires: Windows 10/11, Windows Terminal, Claude Code installed.

$ErrorActionPreference = 'Stop'

Write-Host 'Claude Code Taskbar Badge installer' -ForegroundColor Cyan
Write-Host ''

$claudeDir = Join-Path $env:USERPROFILE '.claude'
if (-not (Test-Path $claudeDir)) {
    Write-Host "ERROR: $claudeDir not found. Install Claude Code first." -ForegroundColor Red
    exit 1
}

$scriptsDir = Join-Path $claudeDir 'scripts'
if (-not (Test-Path $scriptsDir)) { New-Item -ItemType Directory -Path $scriptsDir | Out-Null }

# Embedded script blobs (base64)
$blobs = @{
    'taskbar-state.ps1' = ''
    'taskbar-session-start.ps1' = ''
    'taskbar-watchdog.ps1' = ''
    'taskbar-watcher.ps1' = ''
    'taskbar-sound-picker.ps1' = ''
    'taskbar-play-sound.ps1' = ''
    'taskbar-notification.ps1' = ''
}

# Decode and write each script
foreach ($name in $blobs.Keys) {
    $path = Join-Path $scriptsDir $name
    $bytes = [Convert]::FromBase64String($blobs[$name])
    $content = [System.Text.Encoding]::UTF8.GetString($bytes)
    Set-Content -Path $path -Value $content -Encoding UTF8 -NoNewline
    Write-Host "  wrote $path"
}

# Patch settings.json - merge hooks block
$settingsPath = Join-Path $claudeDir 'settings.json'
if (-not (Test-Path $settingsPath)) {
    Write-Host "  creating new settings.json"
    Set-Content -Path $settingsPath -Value '{}' -Encoding UTF8
}

$settings = Get-Content $settingsPath -Raw -Encoding UTF8 | ConvertFrom-Json

$badgePath = (Join-Path $scriptsDir 'taskbar-session-start.ps1') -replace '\\', '/'
$statePath = (Join-Path $scriptsDir 'taskbar-state.ps1') -replace '\\', '/'

$notifyPath = (Join-Path $scriptsDir 'taskbar-notification.ps1') -replace '\\', '/'

$newHooks = [ordered]@{
    SessionStart = @( @{ hooks = @( @{ type = 'command'; command = "powershell.exe -NoProfile -STA -ExecutionPolicy Bypass -File $badgePath"; shell = 'bash' } ) } )
    UserPromptSubmit = @( @{ hooks = @( @{ type = 'command'; command = "powershell.exe -NoProfile -ExecutionPolicy Bypass -File $statePath -State working"; shell = 'bash' } ) } )
    PreToolUse = @( @{ matcher = 'AskUserQuestion|ExitPlanMode'; hooks = @( @{ type = 'command'; command = "powershell.exe -NoProfile -ExecutionPolicy Bypass -File $statePath -State waiting"; shell = 'bash' } ) } )
    PostToolUse = @( @{ hooks = @( @{ type = 'command'; command = "powershell.exe -NoProfile -ExecutionPolicy Bypass -File $statePath -State working"; shell = 'bash' } ) } )
    Stop = @( @{ hooks = @( @{ type = 'command'; command = "powershell.exe -NoProfile -ExecutionPolicy Bypass -File $statePath -State done"; shell = 'bash' } ) } )
    Notification = @( @{ hooks = @( @{ type = 'command'; command = "powershell.exe -NoProfile -ExecutionPolicy Bypass -File $notifyPath"; shell = 'bash' } ) } )
}

if (-not $settings.hooks) {
    $settings | Add-Member -NotePropertyName hooks -NotePropertyValue (New-Object PSObject) -Force
}

foreach ($evt in $newHooks.Keys) {
    $settings.hooks | Add-Member -NotePropertyName $evt -NotePropertyValue $newHooks[$evt] -Force
}

$settings | ConvertTo-Json -Depth 20 | Set-Content -Path $settingsPath -Encoding UTF8
Write-Host "  patched $settingsPath"
Write-Host ''
Write-Host 'Install complete.' -ForegroundColor Green
Write-Host 'Restart Claude Code in Windows Terminal to activate.'
Write-Host ''

$pickerPath = Join-Path $scriptsDir 'taskbar-sound-picker.ps1'
$soundConfig = Join-Path $scriptsDir 'taskbar-sound.json'

function Test-Sound {
    param([string]$Target)
    if (-not (Test-Path $soundConfig)) { Write-Host "No sound configured for $Target." -ForegroundColor Yellow; return }
    try {
        $cfg = Get-Content $soundConfig -Raw | ConvertFrom-Json
        $wav = $cfg.PSObject.Properties[$Target]
        if ($wav -and $wav.Value -and (Test-Path $wav.Value)) {
            Write-Host "Playing [$Target]: $($wav.Value)"
            (New-Object System.Media.SoundPlayer $wav.Value).PlaySync()
        } else {
            Write-Host "Current $Target sound: NONE (silent)"
        }
    } catch { Write-Host "Error: $_" -ForegroundColor Red }
}

foreach ($target in @('waiting', 'done')) {
    while ($true) {
        $ans = Read-Host "Sound for [$target]: [Y]configure / [N]skip / [T]est current"
        $a = if ($ans) { $ans.ToLower() } else { 'y' }
        if ($a -match '^y') { & $pickerPath -Target $target; break }
        if ($a -match '^n') { break }
        if ($a -match '^t') { Test-Sound -Target $target; continue }
        Write-Host 'Invalid. Type Y, N, or T.' -ForegroundColor Yellow
    }
}

Write-Host ''
Write-Host 'Press Enter to close...'
Read-Host | Out-Null
